import React, { useState, useEffect } from 'react';
import { ethers } from 'ethers';
import { useWallet } from './context/WalletContext';
import { getTokenBalance, getPoolInfo, getLPBalance, swap as swapTokens, addLiquidity as addLiquidityFunc, removeLiquidity as removeLiquidityFunc, getTokenContract, getPoolContract } from './hooks/useContracts';

const Header = ({ openModal }) => {
  const { account, balance, isConnected, connectWallet, disconnectWallet } = useWallet();

  const formatAddress = (addr) => {
    if (!addr) return '';
    return `${addr.substring(0, 6)}...${addr.substring(addr.length - 4)}`;
  };

  return (
    <div style={styles.header}>
      <div style={styles.headerContent}>
        <div style={styles.logo}>
          <span style={{ fontSize: '24px', marginRight: '8px' }}>📊</span>
          <span style={styles.logoText}>DeFi DEX</span>
        </div>
        
        <div style={styles.nav}>
          <button 
            style={styles.navButton}
            onClick={() => openModal('swap')}
          >
            🔄 Swap
          </button>
          <button 
            style={styles.navButton}
            onClick={() => openModal('liquidity')}
          >
            💧 Liquidity
          </button>
          <button 
            style={styles.navButton}
            onClick={() => openModal('positions')}
          >
            📍 Positions
          </button>
        </div>

        <div style={styles.wallet}>
          {isConnected ? (
            <div style={styles.connectedWallet}>
              <div style={styles.balanceInfo}>
                <div style={styles.balanceAmount}>{parseFloat(balance).toFixed(3)} ETH</div>
                <div style={styles.balanceLabel}>Balance</div>
              </div>
              <span style={styles.address}>{formatAddress(account)}</span>
              <button
                style={{ ...styles.button, ...styles.disconnectBtn }}
                onClick={disconnectWallet}
              >
                Disconnect
              </button>
            </div>
          ) : (
            <button
              style={{ ...styles.button, ...styles.connectBtn }}
              onClick={connectWallet}
            >
              Connect MetaMask
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

const SwapModal = ({ isOpen, onClose, poolAddress, tokens, deploymentAddresses }) => {
  const { provider, signer, account } = useWallet();
  const [amountIn, setAmountIn] = useState('');
  const [slippage, setSlippage] = useState('0.5');
  const [isLoading, setIsLoading] = useState(false);
  const [txStatus, setTxStatus] = useState(null);
  const [estimatedOut, setEstimatedOut] = useState('0');

  if (!isOpen || !deploymentAddresses) return null;

  const handleClose = () => {
    setAmountIn('');
    setTxStatus(null);
    onClose();
  };

  const handleSwap = async () => {
    if (!amountIn || !signer) {
      setTxStatus({ success: false, message: 'Please enter amount and connect wallet' });
      return;
    }

    setIsLoading(true);
    setTxStatus(null);

    try {
      // Use USDC as tokenIn and DAI as tokenOut for USDC/DAI pool
      const tokenIn = deploymentAddresses.tokenA;
      const minAmountOut = ethers.utils.parseEther(estimatedOut).mul(100 - parseInt(slippage)).div(100);

      setTxStatus({ success: null, message: 'Approving tokens...' });

      // Approve token
      const tokenContract = getTokenContract(tokenIn, signer);
      const decimals = 6; // USDC has 6 decimals
      const formattedAmount = ethers.utils.parseUnits(amountIn, decimals);

      let approveTx = await tokenContract.approve(deploymentAddresses.poolAB, formattedAmount);
      await approveTx.wait();

      setTxStatus({ success: null, message: 'Executing swap...' });

      // Execute swap
      const poolContract = getPoolContract(deploymentAddresses.poolAB, signer);
      const swapTx = await poolContract.swap(formattedAmount, 0, tokenIn);
      const receipt = await swapTx.wait();

      setTxStatus({
        success: true,
        message: `✅ Swap successful! TX: ${receipt.transactionHash.slice(0, 10)}...`
      });

      setAmountIn('');
      setTimeout(() => {
        handleClose();
      }, 2000);
    } catch (error) {
      console.error('Swap error:', error);
      setTxStatus({
        success: false,
        message: `❌ Swap failed: ${error.message.slice(0, 50)}`
      });
    } finally {
      setIsLoading(false);
    }
  };

  const calculateOutput = (amount) => {
    if (!amount || !deploymentAddresses) return '0';
    // Simple estimation: 1:1 ratio for demo (in reality would query pool reserves)
    return amount;
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      setEstimatedOut(calculateOutput(amountIn));
    }, 300);
    return () => clearTimeout(timer);
  }, [amountIn, deploymentAddresses]);

  return (
    <div style={styles.modalOverlay} onClick={handleClose}>
      <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
        <div style={styles.modalHeader}>
          <h2>🔄 Swap Tokens</h2>
          <button style={styles.closeBtn} onClick={handleClose}>✕</button>
        </div>

        <div style={styles.modalContent}>
          <div style={styles.inputGroup}>
            <label style={styles.label}>You Pay (USDC)</label>
            <input
              type="number"
              placeholder="0.0"
              value={amountIn}
              onChange={(e) => setAmountIn(e.target.value)}
              style={styles.input}
              disabled={isLoading}
            />
            <div style={styles.tokenInfo}>USDC (6 decimals)</div>
          </div>

          <div style={styles.swapArrow}>⬇️</div>

          <div style={styles.inputGroup}>
            <label style={styles.label}>You Receive (DAI)</label>
            <input
              type="text"
              value={estimatedOut}
              disabled
              style={{ ...styles.input, ...styles.disabledInput }}
            />
            <div style={styles.tokenInfo}>DAI (18 decimals)</div>
          </div>

          <div style={styles.slippageControl}>
            <label style={styles.label}>Slippage Tolerance</label>
            <div style={styles.slippageOptions}>
              {['0.1', '0.5', '1.0'].map((val) => (
                <button
                  key={val}
                  style={{
                    ...styles.slippageBtn,
                    ...(slippage === val ? styles.slippageBtnActive : {}),
                  }}
                  onClick={() => setSlippage(val)}
                  disabled={isLoading}
                >
                  {val}%
                </button>
              ))}
              <input
                type="number"
                value={slippage}
                onChange={(e) => setSlippage(e.target.value)}
                style={styles.slippageInput}
                disabled={isLoading}
              />
            </div>
          </div>

          {txStatus && (
            <div style={{
              ...styles.txStatus,
              backgroundColor: txStatus.success ? '#10b981' : txStatus.success === null ? '#f59e0b' : '#ef4444',
            }}>
              {txStatus.message}
            </div>
          )}

          <button
            style={{...styles.button, ...styles.primaryBtn, opacity: isLoading ? 0.6 : 1}}
            onClick={handleSwap}
            disabled={isLoading || !amountIn}
          >
            {isLoading ? '⏳ Processing...' : 'Swap'}
          </button>
        </div>
      </div>
    </div>
  );
};

const LiquidityModal = ({ isOpen, onClose, poolAddress, tokens }) => {
  const [tab, setTab] = useState('add');
  const [amount0, setAmount0] = useState('');
  const [amount1, setAmount1] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [txStatus, setTxStatus] = useState(null);

  if (!isOpen) return null;

  const handleClose = () => {
    setAmount0('');
    setAmount1('');
    setTxStatus(null);
    onClose();
  };

  return (
    <div style={styles.modalOverlay} onClick={handleClose}>
      <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
        <div style={styles.modalHeader}>
          <h2>💧 Liquidity Management</h2>
          <button style={styles.closeBtn} onClick={handleClose}>✕</button>
        </div>

        <div style={styles.tabs}>
          <button
            style={{
              ...styles.tab,
              ...(tab === 'add' ? styles.tabActive : {}),
            }}
            onClick={() => setTab('add')}
          >
            Add Liquidity
          </button>
          <button
            style={{
              ...styles.tab,
              ...(tab === 'remove' ? styles.tabActive : {}),
            }}
            onClick={() => setTab('remove')}
          >
            Remove Liquidity
          </button>
        </div>

        <div style={styles.modalContent}>
          {tab === 'add' ? (
            <>
              <div style={styles.inputGroup}>
                <label style={styles.label}>{tokens?.token0}</label>
                <input
                  type="number"
                  placeholder="0.0"
                  value={amount0}
                  onChange={(e) => setAmount0(e.target.value)}
                  style={styles.input}
                />
              </div>

              <div style={styles.plus}>+</div>

              <div style={styles.inputGroup}>
                <label style={styles.label}>{tokens?.token1}</label>
                <input
                  type="number"
                  placeholder="0.0"
                  value={amount1}
                  onChange={(e) => setAmount1(e.target.value)}
                  style={styles.input}
                />
              </div>

              <div style={styles.info}>
                <strong>You will receive LP tokens representing your position</strong>
              </div>
            </>
          ) : (
            <>
              <div style={styles.inputGroup}>
                <label style={styles.label}>LP Tokens to Remove</label>
                <input
                  type="number"
                  placeholder="0.0"
                  value={amount0}
                  onChange={(e) => setAmount0(e.target.value)}
                  style={styles.input}
                />
              </div>

              <div style={styles.info}>
                <strong>You will receive both tokens back proportionally</strong>
              </div>
            </>
          )}

          {txStatus && (
            <div style={{
              ...styles.txStatus,
              backgroundColor: txStatus.success ? '#10b981' : '#ef4444',
            }}>
              {txStatus.message}
            </div>
          )}

          <button
            style={{...styles.button, ...styles.primaryBtn}}
            onClick={() => {}}
            disabled={isLoading}
          >
            {isLoading ? 'Processing...' : (tab === 'add' ? 'Add Liquidity' : 'Remove Liquidity')}
          </button>
        </div>
      </div>
    </div>
  );
};

